using SiteInspector.Server.Services;
using SiteInspector.Shared.Models;

var builder = WebApplication.CreateBuilder(args);

// Add services to the container
builder.Services.AddSingleton<InMemoryStore>();
builder.Services.AddCors(options =>
{
    options.AddPolicy("AllowAll", builder =>
    {
        builder.AllowAnyOrigin()
               .AllowAnyMethod()
               .AllowAnyHeader();
    });
});

var app = builder.Build();

// Configure the HTTP request pipeline
app.UseCors("AllowAll");
app.UseStaticFiles();
app.UseHttpsRedirection();

// Sync endpoint - accepts client data and returns all server data
app.MapPost("/api/sync", (SyncPayload payload, InMemoryStore store) =>
{
    // Upsert all sites from client
    foreach (var site in payload.Sites)
    {
        store.UpsertSite(site);
    }

    // Upsert all inspections from client
    foreach (var inspection in payload.Inspections)
    {
        store.UpsertInspection(inspection);
    }

    // Return all server data
    return new SyncPayload
    {
        Sites = store.GetAllSites(),
        Inspections = store.GetAllInspections()
    };
})
.WithName("Sync")
.WithOpenApi();

// Photo upload endpoint
app.MapPost("/api/photos/{inspectionId}", async (string inspectionId, IFormFile file, InMemoryStore store) =>
{
    if (file.Length == 0)
    {
        return Results.BadRequest("File is empty");
    }

    using var memoryStream = new MemoryStream();
    await file.CopyToAsync(memoryStream);
    var fileBytes = memoryStream.ToArray();

    store.SavePhoto(inspectionId, file.FileName, fileBytes);

    return Results.Ok(new { inspectionId, fileName = file.FileName });
})
.WithName("UploadPhoto")
.WithOpenApi();

// Photo download endpoint
app.MapGet("/api/photos/{inspectionId}/{fileName}", (string inspectionId, string fileName, InMemoryStore store) =>
{
    var photoBytes = store.GetPhoto(inspectionId, fileName);

    if (photoBytes == null)
    {
        return Results.NotFound();
    }

    // Determine content type based on file extension
    var contentType = Path.GetExtension(fileName).ToLower() switch
    {
        ".jpg" or ".jpeg" => "image/jpeg",
        ".png" => "image/png",
        ".gif" => "image/gif",
        ".webp" => "image/webp",
        _ => "application/octet-stream"
    };

    return Results.File(photoBytes, contentType, fileName);
})
.WithName("GetPhoto")
.WithOpenApi();

app.Run();

