namespace SiteInspector.Client.Services;

public class ConnectivityService : IDisposable
{
    private readonly SyncService _syncService;
    private readonly Timer _timer;
    private bool _isOnline;

    public bool IsOnline => _isOnline;
    public event Action<bool>? OnConnectivityChanged;

    public ConnectivityService(SyncService syncService)
    {
        _syncService = syncService;
        _timer = new Timer(15_000); // Check every 15 seconds
        _timer.Elapsed += async (_, _) => await CheckConnectivityAsync();
        _timer.AutoReset = true;
    }

    public void Start() => _timer.Start();

    public async Task CheckConnectivityAsync()
    {
        var wasOnline = _isOnline;
        _isOnline = await _syncService.IsOnlineAsync();

        if (_isOnline && !wasOnline)
        {
            OnConnectivityChanged?.Invoke(true);
            await _syncService.SyncAsync();
        }
        else if (!_isOnline && wasOnline)
        {
            OnConnectivityChanged?.Invoke(false);
        }
    }

    public void Dispose()
    {
        _timer.Dispose();
    }
}

