{"path": "/tmp/sv-fe8df4230eb744a78f95c20e61a4b10e/src/SiteInspector.Client/Services/SyncService.cs", "file_text": "using System.Net.Http.Json;
using SiteInspector.Shared.Models;

namespace SiteInspector.Client.Services;

public class SyncService
{
    private readonly HttpClient _http;
    private readonly OfflineStorageService _storage;
    private bool _isSyncing;

    public event Action<SyncStatus>? OnSyncStatusChanged;
    public SyncStatus CurrentStatus { get; private set; } = SyncStatus.Idle;

    public SyncService(HttpClient http, OfflineStorageService storage)
    {
        _http = http;
        _storage = storage;
    }

    public async Task<bool> IsOnlineAsync()
    {
        try
        {
            using var cts = new CancellationTokenSource(TimeSpan.FromSeconds(3));
            var response = await _http.GetAsync("api/health", cts.Token);
            return response.IsSuccessStatusCode;
        }
        catch
        {
            return false;
        }
    }

    public async Task SyncAsync()
    {
        if (_isSyncing) return;
        _isSyncing = true;
        SetStatus(SyncStatus.Syncing);

        try
        {
            var unsyncedSites = await _storage.GetUnsyncedSitesAsync();
            var unsyncedInspections = await _storage.GetUnsyncedInspectionsAsync();

            if (unsyncedSites.Count == 0 && unsyncedInspections.Count == 0)
            {
                SetStatus(SyncStatus.Idle);
                return;
            }

            var payload = new SyncPayload
            {
                Sites = unsyncedSites,
                Inspections = unsyncedInspections
            };

            var response = await _http.PostAsJsonAsync("api/sync", payload);
            if (response.IsSuccessStatusCode)
            {
                foreach (var site in unsyncedSites)
                    await _storage.MarkSiteSyncedAsync(site.Id);
                foreach (var inspection in unsyncedInspections)
                    await _storage.MarkInspectionSyncedAsync(inspection.Id);

                // Upload photos for unsynced inspections
                foreach (var inspection in unsyncedInspections)
                {
                    var photos = await _storage.GetPhotosForInspectionAsync(inspection.Id);
                    foreach (var photo in photos)
                    {
                        await UploadPhotoAsync(inspection.Id, photo);
                    }
                }

                SetStatus(SyncStatus.Success);
            }
            else
            {
                SetStatus(SyncStatus.Error);
            }
        }
        catch
        {
            SetStatus(SyncStatus.Error);
        }
        finally
        {
            _isSyncing = false;
        }
    }

    private async Task UploadPhotoAsync(string inspectionId, PhotoRecord photo)
    {
        try
        {
            var bytes = Convert.FromBase64String(photo.Data);
            using var content = new MultipartFormDataContent();
            content.Add(new ByteArrayContent(bytes), "file", photo.FileName);
            await _http.PostAsync($"api/photos/{inspectionId}", content);
        }
        catch
        {
            // Photo upload failures are non-fatal; will retry on next sync
        }
    }

    private void SetStatus(SyncStatus status)
    {
        CurrentStatus = status;
        OnSyncStatusChanged?.Invoke(status);
    }
}

public enum SyncStatus
{
    Idle,
    Syncing,
    Success,
    Error
}
"}

{"path": "/tmp/sv-fe8df4230eb744a78f95c20e61a4b10e/src/SiteInspector.Client/Services/ConnectivityService.cs", "file_text": "using System.Timers;
using Timer = System.Timers.Timer;

namespace SiteInspector.Client.Services;

public class ConnectivityService : IDisposable
{
    private readonly SyncService _syncService;
    private readonly Timer _timer;
    private bool _isOnline;

    public bool IsOnline => _isOnline;
    public event Action<bool>? OnConnectivityChanged;

    public ConnectivityService(SyncService syncService)
    {
        _syncService = syncService;
        _timer = new Timer(15_000); // Check every 15 seconds
        _timer.Elapsed += async (_, _) => await CheckConnectivityAsync();
        _timer.AutoReset = true;
    }

    public void Start() => _timer.Start();

    public async Task CheckConnectivityAsync()
    {
        var wasOnline = _isOnline;
        _isOnline = await _syncService.IsOnlineAsync();

        if (_isOnline && !wasOnline)
        {
            OnConnectivityChanged?.Invoke(true);
            await _syncService.SyncAsync();
        }
        else if (!_isOnline && wasOnline)
        {
            OnConnectivityChanged?.Invoke(false);
        }
    }

    public void Dispose()
    {
        _timer.Dispose();
    }
}
"}

