+using Microsoft.JSInterop;
+using SiteInspector.Shared.Models;
+using System.Text.Json;
+
+namespace SiteInspector.Client.Services;
+
+public class OfflineStorageService
+{
+    private readonly IJSRuntime _js;
+    private static readonly JsonSerializerOptions JsonOptions = new()
+    {
+        PropertyNamingPolicy = JsonNamingPolicy.CamelCase,
+        PropertyNameCaseInsensitive = true
+    };
+
+    public OfflineStorageService(IJSRuntime js)
+    {
+        _js = js;
+    }
+
+    // Sites
+    public async Task SaveSiteAsync(Site site)
+    {
+        site.ModifiedAtUtc = DateTime.UtcNow;
+        var obj = JsonSerializer.SerializeToElement(site, JsonOptions);
+        await _js.InvokeVoidAsync("indexedDbInterop.putItem", "sites", obj);
+    }
+
+    public async Task<List<Site>> GetAllSitesAsync()
+    {
+        var result = await _js.InvokeAsync<JsonElement>("indexedDbInterop.getAllItems", "sites");
+        return JsonSerializer.Deserialize<List<Site>>(result.GetRawText(), JsonOptions) ?? [];
+    }
+
+    public async Task<Site?> GetSiteAsync(string id)
+    {
+        var result = await _js.InvokeAsync<JsonElement?>("indexedDbInterop.getItem", "sites", id);
+        if (result == null || result.Value.ValueKind == JsonValueKind.Undefined || result.Value.ValueKind == JsonValueKind.Null)
+            return null;
+        return JsonSerializer.Deserialize<Site>(result.Value.GetRawText(), JsonOptions);
+    }
+
+    public async Task DeleteSiteAsync(string id)
+    {
+        await _js.InvokeVoidAsync("indexedDbInterop.deleteItem", "sites", id);
+    }
+
+    // Inspections
+    public async Task SaveInspectionAsync(Inspection inspection)
+    {
+        inspection.ModifiedAtUtc = DateTime.UtcNow;
+        var obj = JsonSerializer.SerializeToElement(inspection, JsonOptions);
+        await _js.InvokeVoidAsync("indexedDbInterop.putItem", "inspections", obj);
+    }
+
+    public async Task<List<Inspection>> GetAllInspectionsAsync()
+    {
+        var result = await _js.InvokeAsync<JsonElement>("indexedDbInterop.getAllItems", "inspections");
+        return JsonSerializer.Deserialize<List<Inspection>>(result.GetRawText(), JsonOptions) ?? [];
+    }
+
+    public async Task<Inspection?> GetInspectionAsync(string id)
+    {
+        var result = await _js.InvokeAsync<JsonElement?>("indexedDbInterop.getItem", "inspections", id);
+        if (result == null || result.Value.ValueKind == JsonValueKind.Undefined || result.Value.ValueKind == JsonValueKind.Null)
+            return null;
+        return JsonSerializer.Deserialize<Inspection>(result.Value.GetRawText(), JsonOptions);
+    }
+
+    public async Task DeleteInspectionAsync(string id)
+    {
+        await _js.InvokeVoidAsync("indexedDbInterop.deleteItem", "inspections", id);
+    }
+
+    public async Task<List<Inspection>> GetInspectionsForSiteAsync(string siteId)
+    {
+        var all = await GetAllInspectionsAsync();
+        return all.Where(i => i.SiteId == siteId).OrderByDescending(i => i.InspectionDateUtc).ToList();
+    }
+
+    // Photos
+    public async Task SavePhotoAsync(string inspectionId, string fileName, string contentType, string base64Data)
+    {
+        var id = Guid.NewGuid().ToString();
+        await _js.InvokeVoidAsync("indexedDbInterop.putPhoto", id, inspectionId, fileName, contentType, base64Data);
+    }
+
+    public async Task<List<PhotoRecord>> GetPhotosForInspectionAsync(string inspectionId)
+    {
+        var result = await _js.InvokeAsync<JsonElement>("indexedDbInterop.getPhotosByInspection", inspectionId);
+        return JsonSerializer.Deserialize<List<PhotoRecord>>(result.GetRawText(), JsonOptions) ?? [];
+    }
+
+    public async Task DeletePhotoAsync(string id)
+    {
+        await _js.InvokeVoidAsync("indexedDbInterop.deleteItem", "photos", id);
+    }
+
+    // Sync helpers
+    public async Task<List<Site>> GetUnsyncedSitesAsync()
+    {
+        var all = await GetAllSitesAsync();
+        return all.Where(s => !s.IsSynced).ToList();
+    }
+
+    public async Task<List<Inspection>> GetUnsyncedInspectionsAsync()
+    {
+        var all = await GetAllInspectionsAsync();
+        return all.Where(i => !i.IsSynced).ToList();
+    }
+
+    public async Task MarkSiteSyncedAsync(string id)
+    {
+        var site = await GetSiteAsync(id);
+        if (site != null)
+        {
+            site.IsSynced = true;
+            await SaveSiteAsync(site);
+        }
+    }
+
+    public async Task MarkInspectionSyncedAsync(string id)
+    {
+        var inspection = await GetInspectionAsync(id);
+        if (inspection != null)
+        {
+            inspection.IsSynced = true;
+            await SaveInspectionAsync(inspection);
+        }
+    }
+}
