namespace SiteInspector.Shared.Models;

/// <summary>
/// Represents a construction site entity.
/// </summary>
public class Site
{
    /// <summary>
    /// Gets or sets the unique identifier (GUID string).
    /// </summary>
    public string Id { get; set; } = string.Empty;

    /// <summary>
    /// Gets or sets the site name.
    /// </summary>
    public string Name { get; set; } = string.Empty;

    /// <summary>
    /// Gets or sets the site address.
    /// </summary>
    public string Address { get; set; } = string.Empty;

    /// <summary>
    /// Gets or sets the notes for the site.
    /// </summary>
    public string Notes { get; set; } = string.Empty;

    /// <summary>
    /// Gets or sets the UTC timestamp when the site was created.
    /// </summary>
    public DateTime CreatedAtUtc { get; set; }

    /// <summary>
    /// Gets or sets the UTC timestamp when the site was last modified.
    /// </summary>
    public DateTime ModifiedAtUtc { get; set; }

    /// <summary>
    /// Gets or sets a value indicating whether the site has been synced.
    /// </summary>
    public bool IsSynced { get; set; }
}

namespace SiteInspector.Shared.Models;

/// <summary>
/// Represents the status of an inspection.
/// </summary>
public enum InspectionStatus
{
    /// <summary>
    /// Inspection is in draft status and not yet started.
    /// </summary>
    Draft,

    /// <summary>
    /// Inspection is currently in progress.
    /// </summary>
    InProgress,

    /// <summary>
    /// Inspection has been completed.
    /// </summary>
    Completed
}

/// <summary>
/// Represents an inspection visit to a construction site.
/// </summary>
public class Inspection
{
    /// <summary>
    /// Gets or sets the unique identifier (GUID string).
    /// </summary>
    public string Id { get; set; } = string.Empty;

    /// <summary>
    /// Gets or sets the ID of the site being inspected.
    /// </summary>
    public string SiteId { get; set; } = string.Empty;

    /// <summary>
    /// Gets or sets the name of the site (denormalized for convenience).
    /// </summary>
    public string SiteName { get; set; } = string.Empty;

    /// <summary>
    /// Gets or sets the name of the inspector performing the inspection.
    /// </summary>
    public string InspectorName { get; set; } = string.Empty;

    /// <summary>
    /// Gets or sets the UTC timestamp when the inspection was performed.
    /// </summary>
    public DateTime InspectionDateUtc { get; set; }

    /// <summary>
    /// Gets or sets the current status of the inspection.
    /// </summary>
    public InspectionStatus Status { get; set; } = InspectionStatus.Draft;

    /// <summary>
    /// Gets or sets the collection of checklist items for this inspection.
    /// </summary>
    public List<ChecklistItem> ChecklistItems { get; set; } = new();

    /// <summary>
    /// Gets or sets the collection of photos attached to this inspection.
    /// </summary>
    public List<Photo> Photos { get; set; } = new();

    /// <summary>
    /// Gets or sets the UTC timestamp when the inspection was created.
    /// </summary>
    public DateTime CreatedAtUtc { get; set; }

    /// <summary>
    /// Gets or sets the UTC timestamp when the inspection was last modified.
    /// </summary>
    public DateTime ModifiedAtUtc { get; set; }

    /// <summary>
    /// Gets or sets a value indicating whether the inspection has been synced.
    /// </summary>
    public bool IsSynced { get; set; }
}

namespace SiteInspector.Shared.Models;

/// <summary>
/// Represents a wrapper payload for synchronization operations.
/// Contains collections of entities to be synced between client and server.
/// </summary>
public class SyncPayload
{
    /// <summary>
    /// Gets or sets the collection of sites to be synced.
    /// </summary>
    public List<Site> Sites { get; set; } = new();

    /// <summary>
    /// Gets or sets the collection of inspections to be synced.
    /// </summary>
    public List<Inspection> Inspections { get; set; } = new();
}

namespace SiteInspector.Shared.Models;

/// <summary>
/// Represents a construction site entity.
/// </summary>
public class Site
{
    /// <summary>
    /// Gets or sets the unique identifier (GUID string).
    /// </summary>
    public string Id { get; set; } = string.Empty;

    /// <summary>
    /// Gets or sets the site name.
    /// </summary>
    public string Name { get; set; } = string.Empty;

    /// <summary>
    /// Gets or sets the site address.
    /// </summary>
    public string Address { get; set; } = string.Empty;

    /// <summary>
    /// Gets or sets the notes for the site.
    /// </summary>
    public string Notes { get; set; } = string.Empty;

    /// <summary>
    /// Gets or sets the UTC timestamp when the site was created.
    /// </summary>
    public DateTime CreatedAtUtc { get; set; }

    /// <summary>
    /// Gets or sets the UTC timestamp when the site was last modified.
    /// </summary>
    public DateTime ModifiedAtUtc { get; set; }

    /// <summary>
    /// Gets or sets a value indicating whether the site has been synced.
    /// </summary>
    public bool IsSynced { get; set; }
}

namespace SiteInspector.Shared.Models;

/// <summary>
/// Represents the status of an inspection.
/// </summary>
public enum InspectionStatus
{
    /// <summary>
    /// Inspection is in draft status and not yet started.
    /// </summary>
    Draft,

    /// <summary>
    /// Inspection is currently in progress.
    /// </summary>
    InProgress,

    /// <summary>
    /// Inspection has been completed.
    /// </summary>
    Completed
}

/// <summary>
/// Represents an inspection visit to a construction site.
/// </summary>
public class Inspection
{
    /// <summary>
    /// Gets or sets the unique identifier (GUID string).
    /// </summary>
    public string Id { get; set; } = string.Empty;

    /// <summary>
    /// Gets or sets the ID of the site being inspected.
    /// </summary>
    public string SiteId { get; set; } = string.Empty;

    /// <summary>
    /// Gets or sets the name of the site (denormalized for convenience).
    /// </summary>
    public string SiteName { get; set; } = string.Empty;

    /// <summary>
    /// Gets or sets the name of the inspector performing the inspection.
    /// </summary>
    public string InspectorName { get; set; } = string.Empty;

    /// <summary>
    /// Gets or sets the UTC timestamp when the inspection was performed.
    /// </summary>
    public DateTime InspectionDateUtc { get; set; }

    /// <summary>
    /// Gets or sets the current status of the inspection.
    /// </summary>
    public InspectionStatus Status { get; set; } = InspectionStatus.Draft;

    /// <summary>
    /// Gets or sets the collection of checklist items for this inspection.
    /// </summary>
    public List<ChecklistItem> ChecklistItems { get; set; } = new();

    /// <summary>
    /// Gets or sets the collection of photos attached to this inspection.
    /// </summary>
    public List<Photo> Photos { get; set; } = new();

    /// <summary>
    /// Gets or sets the UTC timestamp when the inspection was created.
    /// </summary>
    public DateTime CreatedAtUtc { get; set; }

    /// <summary>
    /// Gets or sets the UTC timestamp when the inspection was last modified.
    /// </summary>
    public DateTime ModifiedAtUtc { get; set; }

    /// <summary>
    /// Gets or sets a value indicating whether the inspection has been synced.
    /// </summary>
    public bool IsSynced { get; set; }
}

namespace SiteInspector.Shared.Models;

/// <summary>
/// Represents a wrapper payload for synchronization operations.
/// Contains collections of entities to be synced between client and server.
/// </summary>
public class SyncPayload
{
    /// <summary>
    /// Gets or sets the collection of sites to be synced.
    /// </summary>
    public List<Site> Sites { get; set; } = new();

    /// <summary>
    /// Gets or sets the collection of inspections to be synced.
    /// </summary>
    public List<Inspection> Inspections { get; set; } = new();
}

const DB_NAME = 'SiteInspectorDb';
const DB_VERSION = 1;

let db = null;

function openDb() {
    return new Promise((resolve, reject) => {
        if (db) { resolve(db); return; }
        const request = indexedDB.open(DB_NAME, DB_VERSION);
        request.onupgradeneeded = (e) => {
            const database = e.target.result;
            if (!database.objectStoreNames.contains('sites')) {
                database.createObjectStore('sites', { keyPath: 'id' });
            }
            if (!database.objectStoreNames.contains('inspections')) {
                database.createObjectStore('inspections', { keyPath: 'id' });
            }
            if (!database.objectStoreNames.contains('photos')) {
                const photoStore = database.createObjectStore('photos', { keyPath: 'id' });
                photoStore.createIndex('inspectionId', 'inspectionId', { unique: false });
            }
        };
        request.onsuccess = (e) => { db = e.target.result; resolve(db); };
        request.onerror = (e) => reject(e.target.error);
    });
}

window.indexedDbInterop = {
    putItem: async function (storeName, item) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readwrite');
            tx.objectStore(storeName).put(item);
            tx.oncomplete = () => resolve();
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    getItem: async function (storeName, id) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readonly');
            const request = tx.objectStore(storeName).get(id);
            request.onsuccess = () => resolve(request.result || null);
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getAllItems: async function (storeName) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readonly');
            const request = tx.objectStore(storeName).getAll();
            request.onsuccess = () => resolve(request.result);
            request.onerror = (e) => reject(e.target.error);
        });
    },

    deleteItem: async function (storeName, id) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readwrite');
            tx.objectStore(storeName).delete(id);
            tx.oncomplete = () => resolve();
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    getItemsByIndex: async function (storeName, indexName, key) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readonly');
            const index = tx.objectStore(storeName).index(indexName);
            const request = index.getAll(key);
            request.onsuccess = () => resolve(request.result);
            request.onerror = (e) => reject(e.target.error);
        });
    },

    putPhoto: async function (id, inspectionId, fileName, contentType, base64Data) {
        const database = await openDb();
        const item = { id, inspectionId, fileName, contentType, data: base64Data };
        return new Promise((resolve, reject) => {
            const tx = database.transaction('photos', 'readwrite');
            tx.objectStore('photos').put(item);
            tx.oncomplete = () => resolve();
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    getPhotosByInspection: async function (inspectionId) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction('photos', 'readonly');
            const index = tx.objectStore('photos').index('inspectionId');
            const request = index.getAll(inspectionId);
            request.onsuccess = () => resolve(request.result);
            request.onerror = (e) => reject(e.target.error);
        });
    }
};

