using System.Collections.Concurrent;
using SiteInspector.Shared.Models;

namespace SiteInspector.Server.Services;

public class InMemoryStore
{
    private readonly ConcurrentDictionary<string, Site> _sites = new();
    private readonly ConcurrentDictionary<string, Inspection> _inspections = new();
    private readonly string _photosDirectory;

    public InMemoryStore()
    {
        _photosDirectory = Path.Combine(Directory.GetCurrentDirectory(), "photos");

        // Create photos directory if it doesn't exist
        if (!Directory.Exists(_photosDirectory))
        {
            Directory.CreateDirectory(_photosDirectory);
        }
    }

    public List<Site> GetAllSites()
    {
        return _sites.Values.ToList();
    }

    public List<Inspection> GetAllInspections()
    {
        return _inspections.Values.ToList();
    }

    public void UpsertSite(Site site)
    {
        if (string.IsNullOrEmpty(site.Id))
        {
            site.Id = Guid.NewGuid().ToString();
        }

        site.ModifiedAtUtc = DateTime.UtcNow;

        _sites.AddOrUpdate(site.Id, site, (key, existing) => site);
    }

    public void UpsertInspection(Inspection inspection)
    {
        if (string.IsNullOrEmpty(inspection.Id))
        {
            inspection.Id = Guid.NewGuid().ToString();
        }

        inspection.ModifiedAtUtc = DateTime.UtcNow;

        _inspections.AddOrUpdate(inspection.Id, inspection, (key, existing) => inspection);
    }

    public void SavePhoto(string inspectionId, string fileName, byte[] data)
    {
        var inspectionPhotosDir = Path.Combine(_photosDirectory, inspectionId);

        if (!Directory.Exists(inspectionPhotosDir))
        {
            Directory.CreateDirectory(inspectionPhotosDir);
        }

        var filePath = Path.Combine(inspectionPhotosDir, fileName);
        File.WriteAllBytes(filePath, data);
    }

    public byte[]? GetPhoto(string inspectionId, string fileName)
    {
        var filePath = Path.Combine(_photosDirectory, inspectionId, fileName);

        if (File.Exists(filePath))
        {
            return File.ReadAllBytes(filePath);
        }

        return null;
    }
}

