using Microsoft.AspNetCore.Components.Web;
using Microsoft.AspNetCore.Components.WebAssembly.Hosting;
using SiteInspector.Client;
using SiteInspector.Client.Services;

var builder = WebAssemblyHostBuilder.CreateDefault(args);
builder.RootComponents.Add<App>("#app");
builder.RootComponents.Add<HeadOutlet>("head::after");

var serverUrl = builder.Configuration["ApiBaseUrl"] ?? "https://localhost:5001";
builder.Services.AddScoped(sp => new HttpClient { BaseAddress = new Uri(serverUrl) });
builder.Services.AddScoped<OfflineStorageService>();
builder.Services.AddScoped<SyncService>();
builder.Services.AddScoped<ConnectivityService>();

await builder.Build().RunAsync();

@page "/"
@using SiteInspector.Client.Services
@inject OfflineStorageService Storage
@inject NavigationManager Nav

<div class="page-header">
    <h1>🏗️ Site Inspector</h1>
</div>

<div class="dashboard">
    <a class="card-link" href="/sites">
        <div class="dash-card">
            <div class="dash-icon">📍</div>
            <div class="dash-label">Sites</div>
            <div class="dash-count">@_siteCount</div>
        </div>
    </a>
    <a class="card-link" href="/inspections">
        <div class="dash-card">
            <div class="dash-icon">📋</div>
            <div class="dash-label">Inspections</div>
            <div class="dash-count">@_inspectionCount</div>
        </div>
