    <a class="card-link" href="/inspections/new">
        <div class="dash-card dash-card-action">
            <div class="dash-icon">➕</div>
            <div class="dash-label">New Inspection</div>
        </div>
    </a>
</div>

@code {
    private int _siteCount;
    private int _inspectionCount;

    protected override async Task OnInitializedAsync()
    {
        var sites = await Storage.GetAllSitesAsync();
        var inspections = await Storage.GetAllInspectionsAsync();
        _siteCount = sites.Count;
        _inspectionCount = inspections.Count;
    }
}

@page "/sites"
@using SiteInspector.Client.Services
@using SiteInspector.Shared.Models
@inject OfflineStorageService Storage
@inject NavigationManager Nav

<div class="page-header">
    <h1>📍 Sites</h1>
    <button class="btn btn-primary" @onclick="ShowAddForm">+ Add Site</button>
</div>

@if (_showForm)
{
    <div class="form-card">
        <div class="form-group">
            <label>Site Name *</label>
            <input type="text" @bind="_newName" class="form-input" placeholder="e.g. Tower Block A" />
        </div>
        <div class="form-group">
            <label>Address</label>
            <input type="text" @bind="_newAddress" class="form-input" placeholder="123 Main St" />
        </div>
        <div class="form-group">
            <label>Notes</label>
            <textarea @bind="_newNotes" class="form-input" rows="2"></textarea>
        </div>
        <div class="form-actions">
            <button class="btn btn-primary" @onclick="SaveSite" disabled="@string.IsNullOrWhiteSpace(_newName)">Save</button>
            <button class="btn btn-secondary" @onclick="CancelForm">Cancel</button>
        </div>
    </div>
}

@if (_sites.Count == 0 && !_showForm)
{
    <div class="empty-state">
        <p>No sites yet. Add your first construction site to get started.</p>
    </div>
}

<div class="list">
    @foreach (var site in _sites)
    {
        <div class="list-item" @onclick="() => Nav.NavigateTo($&quot;/sites/{site.Id}&quot;)">
            <div class="list-item-content">
                <div class="list-item-title">@site.Name</div>
                <div class="list-item-subtitle">@site.Address</div>
            </div>
            <div class="list-item-badge @(site.IsSynced ? "badge-synced" : "badge-pending")">
                @(site.IsSynced ? "✓" : "⏳")
            </div>
        </div>
    }
</div>

@code {
    private List<Site> _sites = [];
    private bool _showForm;
    private string _newName = "";
    private string _newAddress = "";
    private string _newNotes = "";

    protected override async Task OnInitializedAsync()
    {
        await LoadSites();
    }

    private async Task LoadSites()
    {
        _sites = await Storage.GetAllSitesAsync();
        _sites = _sites.OrderBy(s => s.Name).ToList();
    }

    private void ShowAddForm() => _showForm = true;
    private void CancelForm()
    {
        _showForm = false;
        _newName = _newAddress = _newNotes = "";
    }

    private async Task SaveSite()
    {
        var site = new Site
        {
            Id = Guid.NewGuid().ToString(),
            Name = _newName.Trim(),
            Address = _newAddress.Trim(),
            Notes = _newNotes.Trim(),
            CreatedAtUtc = DateTime.UtcNow,
            ModifiedAtUtc = DateTime.UtcNow,
            IsSynced = false
        };
        await Storage.SaveSiteAsync(site);
        CancelForm();
        await LoadSites();
    }
}

@page "/sites/{SiteId}"
@using SiteInspector.Client.Services
@using SiteInspector.Shared.Models
@inject OfflineStorageService Storage
@inject NavigationManager Nav

@if (_site == null)
{
    <p>Loading...</p>
}
else
{
    <div class="page-header">
        <h1>@_site.Name</h1>
    </div>

    <div class="detail-card">
        <div class="detail-row">
            <span class="detail-label">Address</span>
            <span>@(_site.Address ?? "—")</span>
        </div>
        <div class="detail-row">
            <span class="detail-label">Notes</span>
            <span>@(_site.Notes ?? "—")</span>
        </div>
        <div class="detail-row">
            <span class="detail-label">Synced</span>
            <span>@(_site.IsSynced ? "Yes ✓" : "Pending ⏳")</span>
        </div>
    </div>

    <div class="section-header">
        <h2>Inspections</h2>
        <button class="btn btn-primary" @onclick="StartInspection">+ New Inspection</button>
    </div>

    @if (_inspections.Count == 0)
    {
        <div class="empty-state">
            <p>No inspections for this site yet.</p>
        </div>
    }

    <div class="list">
        @foreach (var inspection in _inspections)
        {
            <div class="list-item" @onclick="() => Nav.NavigateTo($&quot;/inspections/{inspection.Id}&quot;)">
                <div class="list-item-content">
                    <div class="list-item-title">@inspection.InspectionDateUtc.ToString("MMM dd, yyyy")</div>
                    <div class="list-item-subtitle">@inspection.InspectorName — @inspection.Status</div>
                </div>
                <div class="list-item-badge @GetStatusClass(inspection.Status)">
                    @GetStatusIcon(inspection.Status)
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter] public string SiteId { get; set; } = "";

    private Site? _site;
    private List<Inspection> _inspections = [];

    protected override async Task OnInitializedAsync()
    {
        _site = await Storage.GetSiteAsync(SiteId);
        _inspections = await Storage.GetInspectionsForSiteAsync(SiteId);
    }

    private void StartInspection()
    {
        Nav.NavigateTo($"/inspections/new?siteId={SiteId}");
    }

    private string GetStatusClass(InspectionStatus status) => status switch
    {
        InspectionStatus.Completed => "badge-success",
        InspectionStatus.InProgress => "badge-warning",
        _ => "badge-default"
    };

    private string GetStatusIcon(InspectionStatus status) => status switch
    {
        InspectionStatus.Completed => "✓",
        InspectionStatus.InProgress => "⚡",
        _ => "📝"
    };
}

@page "/inspections"
@using SiteInspector.Client.Services
@using SiteInspector.Shared.Models
@inject OfflineStorageService Storage
@inject NavigationManager Nav

<div class="page-header">
    <h1>📋 Inspections</h1>
    <button class="btn btn-primary" @onclick='() => Nav.NavigateTo("/inspections/new")'>+ New</button>
</div>

@if (_inspections.Count == 0)
{
    <div class="empty-state">
        <p>No inspections yet. Start one from a site or tap + New.</p>
    </div>
}

<div class="list">
    @foreach (var inspection in _inspections)
    {
        <div class="list-item" @onclick="() => Nav.NavigateTo($&quot;/inspections/{inspection.Id}&quot;)">
            <div class="list-item-content">
                <div class="list-item-title">@inspection.SiteName</div>
                <div class="list-item-subtitle">
                    @inspection.InspectionDateUtc.ToString("MMM dd, yyyy") — @inspection.InspectorName
                </div>
                <div class="list-item-meta">
                    @inspection.ChecklistItems.Count(i => i.Result == ChecklistItemResult.Pass) ✓
                    @inspection.ChecklistItems.Count(i => i.Result == ChecklistItemResult.Fail) ✗
                    @inspection.ChecklistItems.Count(i => i.Result == ChecklistItemResult.NotInspected) pending
                </div>
            </div>
            <div class="list-item-badge @GetStatusClass(inspection.Status)">
                @GetStatusIcon(inspection.Status)
            </div>
        </div>
    }
</div>

@code {
    private List<Inspection> _inspections = [];

    protected override async Task OnInitializedAsync()
    {
        _inspections = await Storage.GetAllInspectionsAsync();
        _inspections = _inspections.OrderByDescending(i => i.InspectionDateUtc).ToList();
    }

    private string GetStatusClass(InspectionStatus status) => status switch
    {
        InspectionStatus.Completed => "badge-success",
        InspectionStatus.InProgress => "badge-warning",
        _ => "badge-default"
    };

    private string GetStatusIcon(InspectionStatus status) => status switch
    {
        InspectionStatus.Completed => "✓",
        InspectionStatus.InProgress => "⚡",
        _ => "📝"
    };
}

