@page "/inspections/{InspectionId}"
@using SiteInspector.Client.Services
@using SiteInspector.Shared.Models
@using Microsoft.AspNetCore.Components.Forms
@inject OfflineStorageService Storage
@inject NavigationManager Nav
@inject IJSRuntime JS

@if (_inspection == null)
{
    <p>Loading...</p>
    return;
}

<div class="page-header">
    <h1>@_inspection.SiteName</h1>
    <span class="status-badge @GetStatusClass(_inspection.Status)">@_inspection.Status</span>
</div>

<div class="inspection-meta">
    <span>📅 @_inspection.InspectionDateUtc.ToString("MMM dd, yyyy")</span>
    <span>👷 @_inspection.InspectorName</span>
</div>

<div class="progress-bar">
    <div class="progress-fill" style="width: @ProgressPercent%"></div>
</div>
<div class="progress-text">@CompletedCount / @_inspection.ChecklistItems.Count items checked</div>

@* Category tabs *@
<div class="category-tabs">
    @foreach (var cat in _categories)
    {
        <button class="tab @(cat == _activeCategory ? "tab-active" : "")" @onclick="() => SetCategory(cat)">
            @cat
            <span class="tab-count">@GetCategoryProgress(cat)</span>
        </button>
    }
</div>

@* Checklist items for active category *@
<div class="checklist">
    @foreach (var item in ActiveItems)
    {
        <div class="checklist-item @GetItemClass(item.Result)">
            <div class="checklist-description">@item.Description</div>
            <div class="checklist-actions">
                <button class="result-btn pass @(item.Result == ChecklistItemResult.Pass ? "active" : "")"
                        @onclick="() => SetResult(item, ChecklistItemResult.Pass)">✓</button>
                <button class="result-btn fail @(item.Result == ChecklistItemResult.Fail ? "active" : "")"
                        @onclick="() => SetResult(item, ChecklistItemResult.Fail)">✗</button>
                <button class="result-btn na @(item.Result == ChecklistItemResult.NotApplicable ? "active" : "")"
                        @onclick="() => SetResult(item, ChecklistItemResult.NotApplicable)">N/A</button>
            </div>
            @if (item.Result == ChecklistItemResult.Fail || !string.IsNullOrEmpty(item.Notes))
            {
                <div class="checklist-notes">
                    <textarea placeholder="Add notes..." @bind="item.Notes" @bind:after="() => SaveDebounced()"
                              class="notes-input" rows="2"></textarea>
                </div>
            }
        </div>
    }
</div>

@* Photos section *@
<div class="section-header">
    <h2>📷 Photos (@_photos.Count)</h2>
    <label class="btn btn-secondary photo-btn">
        Add Photo
        <InputFile OnChange="HandlePhotoUpload" accept="image/*" capture="environment" style="display:none" />
    </label>
</div>

<div class="photo-grid">
    @foreach (var photo in _photos)
    {
        <div class="photo-thumb">
            <img src="data:@photo.ContentType;base64,@photo.Data" alt="@photo.FileName" />
            <button class="photo-delete" @onclick="() => DeletePhoto(photo.Id)">×</button>
        </div>
    }
</div>

@* Actions *@
<div class="inspection-actions">
    @if (_inspection.Status != InspectionStatus.Completed)
    {
        <button class="btn btn-success btn-block" @onclick="CompleteInspection"
                disabled="@(CompletedCount == 0)">
            ✓ Complete Inspection
        </button>
    }
    else
    {
        <div class="completed-banner">✓ Inspection Completed</div>
    }
</div>

@code {
    [Parameter] public string InspectionId { get; set; } = "";

    private Inspection? _inspection;
    private List<PhotoRecord> _photos = [];
    private List<string> _categories = [];
    private string _activeCategory = "";
    private CancellationTokenSource? _saveCts;

    private IEnumerable<ChecklistItem> ActiveItems =>
        _inspection?.ChecklistItems.Where(i => i.Category == _activeCategory) ?? [];

    private int CompletedCount =>
        _inspection?.ChecklistItems.Count(i => i.Result != ChecklistItemResult.NotInspected) ?? 0;

    private int ProgressPercent =>
        _inspection?.ChecklistItems.Count > 0
            ? (int)(CompletedCount * 100.0 / _inspection.ChecklistItems.Count)
            : 0;

    protected override async Task OnInitializedAsync()
    {
        _inspection = await Storage.GetInspectionAsync(InspectionId);
        if (_inspection != null)
        {
            _categories = _inspection.ChecklistItems.Select(i => i.Category).Distinct().ToList();
            _activeCategory = _categories.FirstOrDefault() ?? "";
            _photos = await Storage.GetPhotosForInspectionAsync(InspectionId);
        }
    }

    private void SetCategory(string category) => _activeCategory = category;

    private async Task SetResult(ChecklistItem item, ChecklistItemResult result)
    {
        item.Result = result;
        item.ModifiedAtUtc = DateTime.UtcNow;
        await SaveInspection();
    }

    private async void SaveDebounced()
    {
        _saveCts?.Cancel();
        _saveCts = new CancellationTokenSource();
        try
        {
            await Task.Delay(500, _saveCts.Token);
            await SaveInspection();
        }
        catch (TaskCanceledException) { }
    }

    private async Task SaveInspection()
    {
        if (_inspection == null) return;
        _inspection.IsSynced = false;
        await Storage.SaveInspectionAsync(_inspection);
    }

    private async Task HandlePhotoUpload(InputFileChangeEventArgs e)
    {
        foreach (var file in e.GetMultipleFiles(5))
        {
            if (file.Size > 10 * 1024 * 1024) continue; // Skip files > 10MB

            using var stream = file.OpenReadStream(10 * 1024 * 1024);
            using var ms = new MemoryStream();
            await stream.CopyToAsync(ms);
            var base64 = Convert.ToBase64String(ms.ToArray());

            await Storage.SavePhotoAsync(InspectionId, file.Name, file.ContentType, base64);

            // Update photo metadata on inspection
            _inspection!.Photos.Add(new Photo
            {
                Id = Guid.NewGuid().ToString(),
                InspectionId = InspectionId,
                FileName = file.Name,
                ContentType = file.ContentType,
                SizeBytes = file.Size,
                CreatedAtUtc = DateTime.UtcNow,
                ModifiedAtUtc = DateTime.UtcNow,
                IsSynced = false
            });
        }

        await SaveInspection();
        _photos = await Storage.GetPhotosForInspectionAsync(InspectionId);
        StateHasChanged();
    }

    private async Task DeletePhoto(string photoId)
    {
        await Storage.DeletePhotoAsync(photoId);
        _photos = await Storage.GetPhotosForInspectionAsync(InspectionId);
    }

    private async Task CompleteInspection()
    {
        if (_inspection == null) return;
        _inspection.Status = InspectionStatus.Completed;
        await SaveInspection();
    }

    private string GetStatusClass(InspectionStatus status) => status switch
    {
        InspectionStatus.Completed => "badge-success",
        InspectionStatus.InProgress => "badge-warning",
        _ => "badge-default"
    };

    private string GetItemClass(ChecklistItemResult result) => result switch
    {
        ChecklistItemResult.Pass => "item-pass",
        ChecklistItemResult.Fail => "item-fail",
        ChecklistItemResult.NotApplicable => "item-na",
        _ => ""
    };

    private string GetCategoryProgress(string category)
    {
        var items = _inspection?.ChecklistItems.Where(i => i.Category == category).ToList() ?? [];
        var done = items.Count(i => i.Result != ChecklistItemResult.NotInspected);
        return $"{done}/{items.Count}";
    }
}

