@page "/inspections/{InspectionId}"
@using SiteInspector.Client.Services
@using SiteInspector.Shared.Models
@using Microsoft.AspNetCore.Components.Forms
@inject OfflineStorageService Storage
@inject NavigationManager Nav
@inject IJSRuntime JS

@if (_inspection == null)
{
    <p>Loading...</p>
    return;
}

<div class="page-header">
    <h1>@_inspection.SiteName</h1>
    <span class="status-badge @GetStatusClass(_inspection.Status)">@_inspection.Status</span>
</div>

<div class="inspection-meta">
    <span>📅 @_inspection.InspectionDateUtc.ToString("MMM dd, yyyy")</span>
    <span>👷 @_inspection.InspectorName</span>
</div>

<div class="progress-bar">
    <div class="progress-fill" style="width: @ProgressPercent%"></div>
</div>
<div class="progress-text">@CompletedCount / @_inspection.ChecklistItems.Count items checked</div>

@* Category tabs *@
<div class="category-tabs">
    @foreach (var cat in _categories)
    {
        <button class="tab @(cat == _activeCategory ? "tab-active" : "")" @onclick="() => SetCategory(cat)">
            @cat
            <span class="tab-count">@GetCategoryProgress(cat)</span>
        </button>
    }
</div>

@* Checklist items for active category *@
<div class="checklist">
    @foreach (var item in ActiveItems)
    {
        <div class="checklist-item @GetItemClass(item.Result)">
            <div class="checklist-description">@item.Description</div>
            <div class="checklist-actions">
                <button class="result-btn pass @(item.Result == ChecklistItemResult.Pass ? "active" : "")"
                        @onclick="() => SetResult(item, ChecklistItemResult.Pass)">✓</button>
                <button class="result-btn fail @(item.Result == ChecklistItemResult.Fail ? "active" : "")"
                        @onclick="() => SetResult(item, ChecklistItemResult.Fail)">✗</button>
                <button class="result-btn na @(item.Result == ChecklistItemResult.NotApplicable ? "active" : "")"
                        @onclick="() => SetResult(item, ChecklistItemResult.NotApplicable)">N/A</button>
            </div>
            @if (item.Result == ChecklistItemResult.Fail || !string.IsNullOrEmpty(item.Notes))
            {
                <div class="checklist-notes">
                    <textarea placeholder="Add notes..." @bind="item.Notes" @bind:after="() => SaveDebounced()"
                              class="notes-input" rows="2"></textarea>
                </div>
            }
        </div>
    }
</div>

@* Photos section *@
<div class="section-header">
    <h2>📷 Photos (@_photos.Count)</h2>
    <label class="btn btn-secondary photo-btn">
        Add Photo
        <InputFile OnChange="HandlePhotoUpload" accept="image/*" capture="environment" style="display:none" />
    </label>
</div>

<div class="photo-grid">
    @foreach (var photo in _photos)
    {
        <div class="photo-thumb">
            <img src="data:@photo.ContentType;base64,@photo.Data" alt="@photo.FileName" />
            <button class="photo-delete" @onclick="() => DeletePhoto(photo.Id)">×</button>
        </div>
    }
</div>

@* Actions *@
<div class="inspection-actions">
    @if (_inspection.Status != InspectionStatus.Completed)
    {
        <button class="btn btn-success btn-block" @onclick="CompleteInspection"
                disabled="@(CompletedCount == 0)">
            ✓ Complete Inspection
        </button>
    }
    else
    {
        <div class="completed-banner">✓ Inspection Completed</div>
    }
</div>

