+                        @onclick="() => SetResult(item, ChecklistItemResult.NotApplicable)">N/A</button>
+            </div>
+            @if (item.Result == ChecklistItemResult.Fail || !string.IsNullOrEmpty(item.Notes))
+            {
+                <div class="checklist-notes">
+                    <textarea placeholder="Add notes..." @bind="item.Notes" @bind:after="() => SaveDebounced()"
+                              class="notes-input" rows="2"></textarea>
+                </div>
+            }
+        </div>
+    }
+</div>
+
+@* Photos section *@
+<div class="section-header">
+    <h2>📷 Photos (@_photos.Count)</h2>
+    <label class="btn btn-secondary photo-btn">
+        Add Photo
+        <InputFile OnChange="HandlePhotoUpload" accept="image/*" capture="environment" style="display:none" />
+    </label>
+</div>
+
+<div class="photo-grid">
+    @foreach (var photo in _photos)
+    {
+        <div class="photo-thumb">
+            <img src="data:@photo.ContentType;base64,@photo.Data" alt="@photo.FileName" />
+            <button class="photo-delete" @onclick="() => DeletePhoto(photo.Id)">×</button>
+        </div>
+    }
+</div>
+
+@* Actions *@
+<div class="inspection-actions">
+    @if (_inspection.Status != InspectionStatus.Completed)
+    {
+        <button class="btn btn-success btn-block" @onclick="CompleteInspection"
+                disabled="@(CompletedCount == 0)">
+            ✓ Complete Inspection
+        </button>
+    }
+    else
+    {
+        <div class="completed-banner">✓ Inspection Completed</div>
+    }
+</div>
+
+@code {
+    [Parameter] public string InspectionId { get; set; } = "";
+
+    private Inspection? _inspection;
+    private List<PhotoRecord> _photos = [];
+    private List<string> _categories = [];
+    private string _activeCategory = "";
+    private CancellationTokenSource? _saveCts;
+
+    private IEnumerable<ChecklistItem> ActiveItems =>
+        _inspection?.ChecklistItems.Where(i => i.Category == _activeCategory) ?? [];
+
+    private int CompletedCount =>
+        _inspection?.ChecklistItems.Count(i => i.Result != ChecklistItemResult.NotInspected) ?? 0;
+
+    private int ProgressPercent =>
+        _inspection?.ChecklistItems.Count > 0
+            ? (int)(CompletedCount * 100.0 / _inspection.ChecklistItems.Count)
+            : 0;
+
+    protected override async Task OnInitializedAsync()
+    {
+        _inspection = await Storage.GetInspectionAsync(InspectionId);
+        if (_inspection != null)
+        {
+            _categories = _inspection.ChecklistItems.Select(i => i.Category).Distinct().ToList();
+            _activeCategory = _categories.FirstOrDefault() ?? "";
+            _photos = await Storage.GetPhotosForInspectionAsync(InspectionId);
+        }
+    }
+
+    private void SetCategory(string category) => _activeCategory = category;
+
+    private async Task SetResult(ChecklistItem item, ChecklistItemResult result)
+    {
+        item.Result = result;
+        item.ModifiedAtUtc = DateTime.UtcNow;
+        await SaveInspection();
+    }
+
+    private async void SaveDebounced()
+    {
+        _saveCts?.Cancel();
+        _saveCts = new CancellationTokenSource();
+        try
+        {
+            await Task.Delay(500, _saveCts.Token);
+            await SaveInspection();
+        }
+        catch (TaskCanceledException) { }
+    }
+
+    private async Task SaveInspection()
+    {
+        if (_inspection == null) return;
+        _inspection.IsSynced = false;
+        await Storage.SaveInspectionAsync(_inspection);
+    }
+
+    private async Task HandlePhotoUpload(InputFileChangeEventArgs e)
+    {
+        foreach (var file in e.GetMultipleFiles(5))
+        {
+            if (file.Size > 10 * 1024 * 1024) continue; // Skip files > 10MB
+
+            using var stream = file.OpenReadStream(10 * 1024 * 1024);
+            using var ms = new MemoryStream();
