﻿@inherits LayoutComponentBase
@inject ConnectivityService Connectivity
@inject SyncService Sync
@inject NavigationManager Nav

<div class="app-shell">
    <main class="app-content">
        @Body
    </main>

    <nav class="bottom-nav">
        <a class="nav-item @IsActive("/")" href="/">
            <span class="nav-icon">🏠</span>
            <span class="nav-label">Home</span>
        </a>
        <a class="nav-item @IsActive("/sites")" href="/sites">
            <span class="nav-icon">📍</span>
            <span class="nav-label">Sites</span>
        </a>
        <a class="nav-item @IsActive("/inspections")" href="/inspections">
            <span class="nav-icon">📋</span>
            <span class="nav-label">Inspections</span>
        </a>
        <button class="nav-item sync-btn" @onclick="TriggerSync">
            <span class="nav-icon @SyncAnimClass">🔄</span>
            <span class="nav-label">Sync</span>
        </button>
    </nav>

    <div class="connectivity-bar @(Connectivity.IsOnline ? "online" : "offline")">
        @(Connectivity.IsOnline ? "● Online" : "● Offline — changes saved locally")
    </div>
</div>

@code {
    private string SyncAnimClass => Sync.CurrentStatus == SyncStatus.Syncing ? "spinning" : "";

    protected override void OnInitialized()
    {
        Connectivity.OnConnectivityChanged += OnConnectivityChanged;
        Sync.OnSyncStatusChanged += OnSyncStatusChanged;
        Connectivity.Start();
    }

    private void OnConnectivityChanged(bool _) => InvokeAsync(StateHasChanged);
    private void OnSyncStatusChanged(SyncStatus _) => InvokeAsync(StateHasChanged);

    private async Task TriggerSync() => await Sync.SyncAsync();

    private string IsActive(string path)
    {
        var uri = Nav.ToBaseRelativePath(Nav.Uri);
        if (path == "/") return string.IsNullOrEmpty(uri) ? "active" : "";
        return uri.StartsWith(path.TrimStart('/')) ? "active" : "";
    }
}

